    cursor.moveToFirst();
    ArrayList text = new ArrayList();
    while(!cursor.isAfterLast()) {
    text.add(cursor.getString(cursor.getColumnIndex("YOURCOLUMNNAME")));
    cursor.moveToNext();
    }
    cursor.close();
    return text.toArray(new String[text.size()]);
