    * {@link #mObjects} is modified.
    */
    private boolean mNotifyOnChange = true;
    private Context mContext; 
    private ArrayList mOriginalValues;
    private HRArrayFilter mFilter;
    private LayoutInflater mInflater;
    /**
    * Constructor
    *
    * @param context The current context.
    * @param textViewResourceId The resource ID for a layout file containing a TextView to use when
    * instantiating views.
    */
    public HRArrayAdapter(Context context, int textViewResourceId) {
    init(context, textViewResourceId, 0, new ArrayList());
    }
    /**
    * Constructor
    *
    * @param context The current context.
    * @param resource The resource ID for a layout file containing a layout to use when
    * instantiating views.
    * @param textViewResourceId The id of the TextView within the layout resource to be populated
    */
    public HRArrayAdapter(Context context, int resource, int textViewResourceId) {
    init(context, resource, textViewResourceId, new ArrayList());
    }
