    * Remove all elements from the list.
    */
    public void clear() {
    if (mOriginalValues != null) {
    synchronized (mLock) {
    mOriginalValues.clear();
    }
    } else {
    mObjects.clear();
    }
    if (mNotifyOnChange) notifyDataSetChanged();
    }
    /**
    * Sorts the content of this adapter using the specified comparator.
    *
    * @param comparator The comparator used to sort the objects contained
    * in this adapter.
    */
    public void sort(Comparator comparator) {
    Collections.sort(mObjects, comparator);
    if (mNotifyOnChange) notifyDataSetChanged(); 
    }
    /**
    * {@inheritDoc}
    */
    @Override
    public void notifyDataSetChanged() {
    super.notifyDataSetChanged();
    mNotifyOnChange = true;
    }
    /**
    * Control whether methods that change the list ({@link #add},
    * {@link #insert}, {@link #remove}, {@link #clear}) automatically call
    * {@link #notifyDataSetChanged}. If set to false, caller must
    * manually call notifyDataSetChanged() to have the changes
    * reflected in the attached view.
    *
    * The default is true, and calling notifyDataSetChanged()
    * resets the flag to true.
    *
    * @param notifyOnChange if true, modifications to the list will
    * automatically call {@link
    * #notifyDataSetChanged}
    */
    public void setNotifyOnChange(boolean notifyOnChange) {
    mNotifyOnChange = notifyOnChange;
    }
    private void init(Context context, int resource, int textViewResourceId, List objects) {
    mContext = context;
    mInflater = (LayoutInflater)context.getSystemService(Context.LAYOUT_INFLATER_SERVICE);
    mResource = mDropDownResource = resource;
    mObjects = objects;
    mFieldId = textViewResourceId;
    }
    /**
    * Returns the context associated with this array adapter. The context is used
    * to create views from the resource passed to the constructor.
    *
    * @return The Context associated with this adapter.
    */
    public Context getContext() {
    return mContext;
    }
    /**
    * {@inheritDoc}
    */
    public int getCount() {
    return mObjects.size();
    }
    /**
    * {@inheritDoc}
    */
    public T getItem(int position) {
    return mObjects.get(position);
    }
    /**
    * Returns the position of the specified item in the array.
    *
    * @param item The item to retrieve the position of.
    *
    * @return The position of the specified item.
    */
    public int getPosition(T item) {
    return mObjects.indexOf(item);
    }
    /**
    * {@inheritDoc}
    */
    public long getItemId(int position) {
    return position;
    }
    /**
    * {@inheritDoc}
    */
    public View getView(int position, View convertView, ViewGroup parent) {
    return createViewFromResource(position, convertView, parent, mResource);
    }
    private View createViewFromResource(int position, View convertView, ViewGroup parent,
    int resource) {
    View view;
    TextView text;
    if (convertView == null) {
    view = mInflater.inflate(resource, parent, false);
    } else {
    view = convertView;
    }
    try {
    if (mFieldId == 0) {
    // If no custom field is assigned, assume the whole resource is a TextView
    text = (TextView) view;
    } else {
    // Otherwise, find the TextView field within the layout
    text = (TextView) view.findViewById(mFieldId);
    }
    } catch (ClassCastException e) {
    Log.e("ArrayAdapter", "You must supply a resource ID for a TextView");
    throw new IllegalStateException(
    "ArrayAdapter requires the resource ID to be a TextView", e);
    }
    text.setText(getItem(position).toString());
    return view;
    }
    /**
    * 

    Sets the layout resource to create the drop down views.


    *
    * @param resource the layout resource defining the drop down views
    * @see #getDropDownView(int, android.view.View, android.view.ViewGroup)
    */
    public void setDropDownViewResource(int resource) {
    this.mDropDownResource = resource;
    }
    /**
    * {@inheritDoc}
    */
    @Override
    public View getDropDownView(int position, View convertView, ViewGroup parent) {
    return createViewFromResource(position, convertView, parent, mDropDownResource);
    }
    /**
    * Creates a new ArrayAdapter from external resources. The content of the array is
    * obtained through {@link android.content.res.Resources#getTextArray(int)}.
    *
    * @param context The application's environment.
    * @param textArrayResId The identifier of the array to use as the data source.
    * @param textViewResId The identifier of the layout used to create views.
    *
    * @return An ArrayAdapter.
    */
    public static HRArrayAdapter createFromResource(Context context,
    int textArrayResId, int textViewResId) {
    CharSequence[] strings = context.getResources().getTextArray(textArrayResId);
    return new HRArrayAdapter(context, textViewResId, strings);
    }
    /**
    * {@inheritDoc}
    */
    public HRArrayFilter getFilter() {
    if (mFilter == null) {
    mFilter = new HRArrayFilter();
    }
    return mFilter;
    }
    /**
    * 

    An array filter constrains the content of the array adapter with
    * a prefix. Each item that does not start with the supplied prefix
    * is removed from the list.


    */
    private class HRArrayFilter extends Filter {
    @Override
    protected FilterResults performFiltering(CharSequence prefix) {
    FilterResults results = new FilterResults();
    if (mOriginalValues == null) {
    synchronized (mLock) {
    mOriginalValues = new ArrayList(mObjects);
    }
    }
    if (prefix == null || prefix.length() == 0) {
    synchronized (mLock) {
    ArrayList list = new ArrayList(mOriginalValues);
    results.values = list;
    results.count = list.size();
    }
    } else {
    String prefixString = prefix.toString().toLowerCase();
    ArrayList values = mOriginalValues;
    final int count = values.size();
    final ArrayList newValues = new ArrayList(count);
    final ArrayList noPalatals = new ArrayList();
    for (int i = 0; i < count; i++) {
    final T value = values.get(i);
    final String valueText = value.toString().toLowerCase();
    String valueTextNoPalatals = toNoPalatals(valueText);
    String prefixStringNoPalatals = toNoPalatals(prefixString);
    //Log.d( "DATA NORMAL", valueText + ", " + prefixString );
    //Log.d( "DATA NO PALATALS", valueTextNoPalatals + ", " + prefixStringNoPalatals );
    // First match against the whole, non-splitted value
    if (valueText.startsWith(prefixString) || valueTextNoPalatals.startsWith(prefixStringNoPalatals)) {
    newValues.add(value);
    } else {
    final String[] words = valueText.split(" ");
    final int wordCount = words.length;
    for (int k = 0; k < wordCount; k++) {
    if (words[k].startsWith(prefixString)) {
    newValues.add(value);
    break;
    }
    }
    }
    }
    results.values = newValues;
    results.count = newValues.size();
    }
    return results;
    }
    @Override
    protected void publishResults(CharSequence constraint, FilterResults results) {
    //noinspection unchecked
    mObjects = (List) results.values;
    if (results.count > 0) {
    notifyDataSetChanged();
    } else {
    notifyDataSetInvalidated();
    }
    }
    private String toNoPalatals( String original )
    {
    original = original.replace("\\\\xc4\\\\x8c", "C");
    original = original.replace("\\\\xc4\\\\x86", "C");
    original = original.replace("\\\\xc5\\\\xa0\\\\xc2\\\\xa0", "S");
    original = original.replace("\\\\xc4\\\\x90", "D");
    original = original.replace("\\\\xc5\\\\xbd", "Z");
    original = original.replace("\\\\xc4\\\\x8d", "c");
    original = original.replace("\\\\xc4\\\\x87", "c");
    original = original.replace("\\\\xc5\\\\xa1", "s");
    original = original.replace("\\\\xc4\\\\x91", "d");
    original = original.replace("\\\\xc5\\\\xbe", "z");
    return original;
    }
    }
    }

